// Find contacts with birthdays in the next 7 days or turning 65
const contacts = $input.all();
const today = new Date();
const todayStr = today.toISOString().split('T')[0]; // YYYY-MM-DD
const sevenDaysStr = new Date(today.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

const milestones = [];

for (const item of contacts) {
  const c = item.json;
  const birthDate = c.dateOfBirth || c.customFields?.find(f => f.key === 'date_of_birth')?.value;
  if (!birthDate) continue;

  // Check if birthday is in next 7 days
  const birthMonthDay = birthDate.slice(5, 10); // MM-DD
  const thisYearBirthday = `${today.getFullYear()}-${birthMonthDay}`;

  if (thisYearBirthday >= todayStr && thisYearBirthday <= sevenDaysStr) {
    const age = today.getFullYear() - parseInt(birthDate.split('-')[0]);

    let milestoneType = 'Birthday';
    if (age === 64) milestoneType = 'Turning 65 - Medicare Eligible';
    else if (age === 65) milestoneType = 'Medicare Milestone';
    else if (age === 50) milestoneType = 'Life Insurance Milestone';

    milestones.push({
      ...c,
      milestoneType,
      age,
      birthdayThisYear: thisYearBirthday
    });
  }
}

return milestones.map(c => ({ json: c }));
